// Fail-closed on the bridge secret, then dedupe on the envelope id (at-least-once delivery).
const got = $input.first().json.headers?.['x-gaiada-bridge-secret'];
if (!got || got !== $env.N8N_BRIDGE_SECRET) throw new Error('bad bridge secret');
const e = $input.first().json.body ?? {};
if (e.v !== 1) throw new Error(`unexpected envelope version ${e.v}`);
const store = $getWorkflowStaticData('global');
store.seen = store.seen || {};
const dup = Object.prototype.hasOwnProperty.call(store.seen, e.id);
if (!dup) {
  store.seen[e.id] = Date.now();
  const ids = Object.keys(store.seen);
  if (ids.length > 1000) for (const k of ids.slice(0, ids.length - 1000)) delete store.seen[k];
}
return [{ json: { dup, tenantId: e.tenantId, entityId: e.entityId, at: e.createdAt } }];

// Surface a hub/tool error as a workflow failure (the hub replies 200 with isError on denial).
const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'notify failed');
return [{ json: { ok: true } }];
